}

.ascii-marker::before {
  content: '[';
  color: var(--ascii-accent);
}

.ascii-marker::after {
  content: ']';
  color: var(--ascii-accent);
}

/* Evidence Grid */
.evidence-grid {
  display: grid;
  gap: 1px;
  background: var(--ascii-border);
  border: 1px solid var(--ascii-border);
}

.evidence-grid > * {
  background: var(--background);
  padding: 1rem;
}

/* Typewriter Effect */
@keyframes typewriter {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes blink {
  50% { border-color: transparent; }
}

.typewriter {
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid var(--foreground);
