        setTypedText(asciiArt.slice(0, charIndex + 1));
        charIndex++;
      } else {
        clearInterval(typeInterval);
      }
    }, 5);

    return () => {
      clearTimeout(timeout);
      clearInterval(typeInterval);
    };
  }, [prefersReducedMotion]);

