export default function AdminLoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [passkeySupported, setPasskeySupported] = useState(false);
  const { toast } = useToast();

  // Check WebAuthn support
  useEffect(() => {
    setPasskeySupported(window.PublicKeyCredential !== undefined);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const response = await fetch('/api/admin/auth', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      if (response.ok) {
        toast({
          title: 'Welcome back!',
          description: 'Redirecting to dashboard...',
        });
        window.location.href = '/admin';
      } else {
        const error = await response.json();
        toast({
          title: 'Authentication failed',
          description: error.message || 'Invalid credentials',
          variant: 'destructive',
        });
      }
    } catch {
      toast({
        title: 'Error',
        description: 'Something went wrong. Please try again.',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handlePasskeyLogin = async () => {
    if (!passkeySupported) {
      toast({
        title: 'Passkey not supported',
        description: 'Your browser does not support passkey authentication.',
        variant: 'destructive',
      });
      return;
    }

    setIsLoading(true);

    try {
      // Get challenge from server
      const optionsResponse = await fetch('/api/admin/passkey/auth/options', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });

      if (!optionsResponse.ok) {
        throw new Error('Failed to get authentication options');
      }

      const options = await optionsResponse.json();

      // Trigger WebAuthn
      const credential = await navigator.credentials.get({
        publicKey: options,
      }) as PublicKeyCredential;

      // Verify with server
      const verifyResponse = await fetch('/api/admin/passkey/auth/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email,
          credential: {
            id: credential.id,
            rawId: Array.from(new Uint8Array(credential.rawId)),
            response: {
              authenticatorData: Array.from(new Uint8Array((credential.response as AuthenticatorAssertionResponse).authenticatorData)),
              clientDataJSON: Array.from(new Uint8Array(credential.response.clientDataJSON)),
              signature: Array.from(new Uint8Array((credential.response as AuthenticatorAssertionResponse).signature)),
              userHandle: (credential.response as AuthenticatorAssertionResponse).userHandle 
                ? Array.from(new Uint8Array((credential.response as AuthenticatorAssertionResponse).userHandle!))
                : null,
            },
            type: credential.type,
          },
        }),
      });

      if (verifyResponse.ok) {
        toast({
          title: 'Welcome back!',
          description: 'Authenticated with passkey.',
        });
        window.location.href = '/admin';
      } else {
        throw new Error('Passkey verification failed');
      }
    } catch (error) {
      console.error('Passkey error:', error);
      toast({
        title: 'Passkey failed',
        description: 'Could not authenticate with passkey. Please use password.',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-background via-muted to-background p-4">
      {/* Background ASCII Pattern */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none opacity-[0.02]">
        <pre className="font-mono text-[8px] text-foreground leading-none">
          {Array(50).fill(null).map((_, i) => (
            <div key={i}>
              {Array(100).fill(null).map((_, j) => (
                <span key={j}>{Math.random() > 0.5 ? '1' : '0'}</span>
              ))}
            </div>
          ))}
        </pre>
      </div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="w-full max-w-md relative z-10"
      >
        {/* Logo */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-primary mb-4">
            <Shield className="h-8 w-8 text-primary-foreground" />
          </div>
          <h1 className="text-2xl font-bold mb-2">Admin Portal</h1>
          <p className="text-muted-foreground">Sign in to manage your content</p>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Sign In</CardTitle>
            <CardDescription>
              Enter your credentials to access the dashboard
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              {/* Email */}
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    id="email"
                    type="email"
                    placeholder="admin@douglasmitchell.info"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="pl-9"
                    required
                  />
                </div>
              </div>

              {/* Password */}
              <div className="space-y-2">
                <Label htmlFor="password">Password</Label>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="pl-9 pr-10"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                  >
                    {showPassword ? (
                      <EyeOff className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </button>
                </div>
              </div>

              {/* Remember Me & Forgot Password */}
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <Checkbox
                    id="remember"
                    checked={rememberMe}
                    onCheckedChange={(checked) => setRememberMe(checked as boolean)}
                  />
                  <Label htmlFor="remember" className="text-sm font-normal">
                    Remember me
                  </Label>
                </div>
                <a
                  href="#"
                  className="text-sm text-primary hover:underline"
                >
                  Forgot password?
                </a>
              </div>

              {/* Submit */}
              <Button
                type="submit"
                className="w-full"
                disabled={isLoading}
              >
                {isLoading ? (
                  <span className="flex items-center gap-2">
                    <motion.span
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                    >
                      ◌
                    </motion.span>
                    Signing in...
                  </span>
                ) : (
                  <>
                    Sign In
                    <ArrowRight className="h-4 w-4 ml-2" />
                  </>
                )}
              </Button>
            </form>

            {/* Passkey Option */}
            {passkeySupported && (
              <>
                <div className="relative my-6">
                  <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t" />
                  </div>
                  <div className="relative flex justify-center text-xs uppercase">
                    <span className="bg-card px-2 text-muted-foreground">
                      Or continue with
                    </span>
                  </div>
                </div>

                <Button
                  type="button"
                  variant="outline"
                  className="w-full"
                  onClick={handlePasskeyLogin}
                  disabled={isLoading || !email}
                >
                  <Fingerprint className="h-4 w-4 mr-2" />
                  Sign in with Passkey
                </Button>
              </>
            )}
          </CardContent>
        </Card>

        {/* Footer */}
        <p className="text-center text-sm text-muted-foreground mt-6">
          Protected by enterprise-grade security
        </p>
      </motion.div>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { hashPassword, verifyPassword, createSession, setSessionCookie, checkRateLimit } from '@/lib/auth';
import { env } from '@/lib/env';

// GET /api/admin/auth - Check current session
export async function GET() {
  try {
    // Get session from cookie
    const cookieStore = await import('next/headers').then(m => m.cookies());
    const token = cookieStore.get('admin-session')?.value;

    if (!token) {
      return NextResponse.json({ authenticated: false }, { status: 401 });
    }

    // Verify token
    const { jwtVerify } = await import('jose');
    const secret = new TextEncoder().encode(env.JWT_SECRET || 'fallback-secret');

    try {
      const { payload } = await jwtVerify(token, secret);
      return NextResponse.json({ 
        authenticated: true, 
        user: {
          userId: payload.userId,
          email: payload.email,
          name: payload.name,
          role: payload.role,
        }
      });
    } catch {
      return NextResponse.json({ authenticated: false }, { status: 401 });
    }
  } catch (error) {
    console.error('Auth check error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

// POST /api/admin/auth - Login
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, password } = body;

    // Validation
    if (!email || !password) {
      return NextResponse.json(
        { error: 'Email and password are required' },
        { status: 400 }
      );
    }

    // Rate limiting
    const clientIp = request.headers.get('x-forwarded-for') || 'unknown';
    if (!checkRateLimit(clientIp)) {
      return NextResponse.json(
        { error: 'Too many login attempts. Please try again later.' },
        { status: 429 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'Invalid credentials' },
        { status: 401 }
      );
    }

    // Verify password
    const isValid = await verifyPassword(password, user.passwordHash);

    if (!isValid) {
      return NextResponse.json(
        { error: 'Invalid credentials' },
        { status: 401 }
      );
    }

    // Update last login
    await db.adminUser.update({
      where: { id: user.id },
      data: { lastLoginAt: new Date() },
    });

    // Create session
    const token = await createSession(user.id, user.email, user.name || 'Admin');
    await setSessionCookie(token);

    return NextResponse.json({
      success: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
      },
    });
  } catch (error) {
    console.error('Login error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { deleteSession } from '@/lib/auth';

// POST /api/admin/logout - Logout user
export async function POST() {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get('admin-session')?.value;

    if (token) {
      await deleteSession(token);
    }

    // Clear cookie
    cookieStore.delete('admin-session');

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Logout error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { mkdir, writeFile } from 'fs/promises';
import { existsSync } from 'fs';
import { join, extname, basename } from 'path';
import sharp from 'sharp';
import { v4 as uuidv4 } from 'uuid';

// File type configurations
export const ALLOWED_MIME_TYPES = {
  image: ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/avif', 'image/svg+xml'],
  video: ['video/mp4', 'video/webm', 'video/ogg'],
  audio: ['audio/mpeg', 'audio/wav', 'audio/ogg', 'audio/webm'],
  document: [
    'application/pdf',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/vnd.ms-excel',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'text/plain',
    'text/markdown',
  ],
};

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const UPLOAD_DIR = process.env.UPLOAD_DIR || './public/uploads';

export interface FileValidationResult {
  valid: boolean;
  error?: string;
}

export interface UploadResult {
  success: boolean;
  id?: string;
  filename?: string;
  originalName: string;
  mimeType: string;
  size: number;
  width?: number;
  height?: number;
  duration?: number;
  url?: string;
  thumbnailUrl?: string;
  error?: string;
}

// Validate file type
export function validateFileType(mimeType: string): FileValidationResult {
  const allAllowed = Object.values(ALLOWED_MIME_TYPES).flat();

  if (allAllowed.includes(mimeType)) {
    return { valid: true };
  }

  return {
    valid: false,
    error: `File type ${mimeType} is not allowed. Allowed types: images, videos, audio, documents`,
  };
}

// Validate file size
export function validateFileSize(size: number): FileValidationResult {
  if (size <= MAX_FILE_SIZE) {
    return { valid: true };
  }

  return {
    valid: false,
    error: `File size ${formatFileSize(size)} exceeds maximum of ${formatFileSize(MAX_FILE_SIZE)}`,
  };
}

// Format file size for display
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// Get file category
export function getFileCategory(mimeType: string): 'image' | 'video' | 'audio' | 'document' | 'unknown' {
  if (ALLOWED_MIME_TYPES.image.includes(mimeType)) return 'image';
  if (ALLOWED_MIME_TYPES.video.includes(mimeType)) return 'video';
  if (ALLOWED_MIME_TYPES.audio.includes(mimeType)) return 'audio';
  if (ALLOWED_MIME_TYPES.document.includes(mimeType)) return 'document';
  return 'unknown';
}

// Generate unique filename
export function generateUniqueFilename(originalName: string): string {
  const ext = extname(originalName);
  const uniqueId = uuidv4();
  return `${uniqueId}${ext}`;
}

// Get image dimensions
export async function getImageDimensions(buffer: Buffer): Promise<{ width: number; height: number } | null> {
  try {
    const metadata = await sharp(buffer).metadata();
    if (metadata.width && metadata.height) {
      return { width: metadata.width, height: metadata.height };
    }
    return null;
  } catch {
    return null;
  }
}

// Create thumbnail for images
export async function createThumbnail(
  buffer: Buffer,
  filename: string,
  width: number = 300
): Promise<string | null> {
  try {
    const thumbnailDir = join(UPLOAD_DIR, 'thumbnails');
    if (!existsSync(thumbnailDir)) {
      await mkdir(thumbnailDir, { recursive: true });
    }

    const thumbnailFilename = `thumb-${width}-${filename}`;
    const thumbnailPath = join(thumbnailDir, thumbnailFilename);

    await sharp(buffer)
      .resize(width, null, { withoutEnlargement: true })
      .jpeg({ quality: 80 })
      .toFile(thumbnailPath);

    return `/uploads/thumbnails/${thumbnailFilename}`;
  } catch (error) {
    console.error('Thumbnail creation failed:', error);
    return null;
  }
}

// Optimize image
export async function optimizeImage(buffer: Buffer, mimeType: string): Promise<Buffer> {
  try {
    if (mimeType === 'image/svg+xml') {
      return buffer; // Don't optimize SVGs
    }

    const sharpInstance = sharp(buffer);

    // Resize if too large
    const metadata = await sharpInstance.metadata();
    if (metadata.width && metadata.width > 2048) {
      sharpInstance.resize(2048, null, { withoutEnlargement: true });
    }

    // Convert to WebP for better compression
    if (mimeType !== 'image/webp' && mimeType !== 'image/avif') {
      return await sharpInstance.webp({ quality: 85 }).toBuffer();
    }

    return await sharpInstance.toBuffer();
  } catch {
    return buffer; // Return original if optimization fails
  }
}

// Save file to disk
export async function saveFile(
  buffer: Buffer,
  filename: string,
  category: string
): Promise<string> {
  const categoryDir = join(UPLOAD_DIR, category);

  if (!existsSync(categoryDir)) {
    await mkdir(categoryDir, { recursive: true });
  }

  const filePath = join(categoryDir, filename);
  await writeFile(filePath, buffer);

  return `/uploads/${category}/${filename}`;
}

// Process file upload
export async function processFileUpload(
  file: File,
  options: {
    createThumbnail?: boolean;
    optimizeImages?: boolean;
  } = {}
): Promise<UploadResult> {
  const { createThumbnail: shouldCreateThumbnail = true, optimizeImages = true } = options;

  try {
    // Validate
    const typeValidation = validateFileType(file.type);
    if (!typeValidation.valid) {
      return { success: false, error: typeValidation.error, originalName: file.name, mimeType: file.type, size: file.size };
    }

    const sizeValidation = validateFileSize(file.size);
    if (!sizeValidation.valid) {
      return { success: false, error: sizeValidation.error, originalName: file.name, mimeType: file.type, size: file.size };
    }

    const category = getFileCategory(file.type);
    const uniqueFilename = generateUniqueFilename(file.name);

    // Convert File to Buffer
    const bytes = await file.arrayBuffer();
    let buffer = Buffer.from(bytes);

    let width: number | undefined;
    let height: number | undefined;
    let duration: number | undefined;
    let thumbnailUrl: string | undefined;

    // Process based on file type
    if (category === 'image') {
      // Get dimensions
      const dimensions = await getImageDimensions(buffer);
      if (dimensions) {
        width = dimensions.width;
        height = dimensions.height;
      }

      // Optimize
      if (optimizeImages) {
        buffer = await optimizeImage(buffer, file.type);
      }

      // Create thumbnail
      if (shouldCreateThumbnail && dimensions) {
        thumbnailUrl = await createThumbnail(buffer, uniqueFilename);
      }
    }

    // Save file
    const url = await saveFile(buffer, uniqueFilename, category);

    return {
      success: true,
      id: uuidv4(),
      filename: uniqueFilename,
      originalName: file.name,
      mimeType: file.type,
      size: file.size,
      width,
      height,
      duration,
      url,
      thumbnailUrl,
    };
  } catch (error) {
    console.error('File upload error:', error);
    return {
      success: false,
      error: 'Failed to process file upload',
      originalName: file.name,
      mimeType: file.type,
      size: file.size,
    };
  }
}

// Get file icon based on type
export function getFileIcon(mimeType: string): string {
  const category = getFileCategory(mimeType);

  const icons = {
    image: '🖼️',
    video: '🎬',
    audio: '🎵',
    document: '📄',
    unknown: '📎',
  };

  return icons[category];
}

// Check if file is previewable
export function isPreviewable(mimeType: string): boolean {
  return getFileCategory(mimeType) !== 'unknown';
}

// WebAuthn/Passkey utilities using simple-webauthn
import {
  generateRegistrationOptions,
  verifyRegistrationResponse,
  generateAuthenticationOptions,
  verifyAuthenticationResponse,
  type GenerateRegistrationOptionsOpts,
  type VerifyRegistrationResponseOpts,
  type GenerateAuthenticationOptionsOpts,
  type VerifyAuthenticationResponseOpts,
} from '@simplewebauthn/server';
import type {
  PublicKeyCredentialCreationOptionsJSON,
  PublicKeyCredentialRequestOptionsJSON,
  RegistrationResponseJSON,
  AuthenticationResponseJSON,
} from '@simplewebauthn/types';

// Relying Party configuration
const RP_ID = process.env.PASSKEY_RP_ID || 'localhost';
const RP_NAME = process.env.PASSKEY_RP_NAME || 'Douglas Mitchell Portfolio';
const EXPECTED_ORIGINS = process.env.PASSKEY_EXPECTED_ORIGINS?.split(',') || [
  'http://localhost:3000',
  'https://douglasmitchell.info',
];

// Generate options for registering a new passkey
export async function createRegistrationOptions(
  userId: string,
  userEmail: string,
  userName: string,
  existingCredentialIds: string[] = []
): Promise<PublicKeyCredentialCreationOptionsJSON> {
  const options = await generateRegistrationOptions({
    rpName: RP_NAME,
    rpID: RP_ID,
    userID: userId,
    userName: userEmail,
    userDisplayName: userName,
    attestationType: 'none',
    excludeCredentials: existingCredentialIds.map(id => ({
      id,
      type: 'public-key',
    })),
    authenticatorSelection: {
      residentKey: 'preferred',
      userVerification: 'preferred',
      authenticatorAttachment: 'platform', // Prefer platform authenticators (Touch ID, Windows Hello)
    },
  });

  return options;
}

// Verify registration response from client
export async function verifyRegistration(
  response: RegistrationResponseJSON,
  expectedChallenge: string
): Promise<{
  verified: boolean;
  registrationInfo?: {
    credentialID: string;
    credentialPublicKey: Uint8Array;
    counter: number;
  };
  error?: string;
}> {
  try {
    const verification = await verifyRegistrationResponse({
      response,
      expectedChallenge,
      expectedOrigin: EXPECTED_ORIGINS,
      expectedRPID: RP_ID,
    });

    if (verification.verified && verification.registrationInfo) {
      return {
        verified: true,
        registrationInfo: {
          credentialID: verification.registrationInfo.credentialID,
          credentialPublicKey: verification.registrationInfo.credentialPublicKey,
          counter: verification.registrationInfo.counter,
        },
      };
    }

    return { verified: false, error: 'Registration verification failed' };
  } catch (error) {
    console.error('Registration verification error:', error);
    return { verified: false, error: 'Registration verification failed' };
  }
}

// Generate options for authenticating with a passkey
export async function createAuthenticationOptions(
  credentialIds: string[]
): Promise<PublicKeyCredentialRequestOptionsJSON> {
  const options = await generateAuthenticationOptions({
    rpID: RP_ID,
    allowCredentials: credentialIds.map(id => ({
      id,
      type: 'public-key',
    })),
    userVerification: 'preferred',
  });

  return options;
}

// Verify authentication response from client
export async function verifyAuthentication(
  response: AuthenticationResponseJSON,
  expectedChallenge: string,
  credential: {
    id: string;
    publicKey: Uint8Array;
    counter: number;
  }
): Promise<{
  verified: boolean;
  newCounter?: number;
  error?: string;
}> {
  try {
    const verification = await verifyAuthenticationResponse({
      response,
      expectedChallenge,
      expectedOrigin: EXPECTED_ORIGINS,
      expectedRPID: RP_ID,
      authenticator: {
        credentialID: credential.id,
        credentialPublicKey: credential.publicKey,
        counter: credential.counter,
      },
    });

    if (verification.verified) {
      return {
        verified: true,
        newCounter: verification.authenticationInfo.newCounter,
      };
    }

    return { verified: false, error: 'Authentication verification failed' };
  } catch (error) {
    console.error('Authentication verification error:', error);
    return { verified: false, error: 'Authentication verification failed' };
  }
}

// Base64URL encoding helpers
export function base64URLDecode(base64url: string): Uint8Array {
  const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function base64URLEncode(buffer: Uint8Array): string {
  const binary = String.fromCharCode(...buffer);
  const base64 = btoa(binary);
  return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { createRegistrationOptions } from '@/lib/passkeys';
import { env } from '@/lib/env';

// POST /api/admin/passkey/register/options
// Generate registration options for a new passkey
export async function POST(request: NextRequest) {
  try {
    // Check if passkeys are enabled
    if (!env.ENABLE_PASSKEYS) {
      return NextResponse.json(
        { error: 'Passkey authentication is not enabled' },
        { status: 400 }
      );
    }

    const body = await request.json();
    const { email } = body;

    if (!email) {
      return NextResponse.json(
        { error: 'Email is required' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
      include: { passkeys: true },
    });

    if (!user) {
      // Don't reveal if user exists for security
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Get existing credential IDs to exclude
    const existingCredentialIds = user.passkeys.map(p => p.credentialId);

    // Generate registration options
    const options = await createRegistrationOptions(
      user.id,
      user.email,
      user.name || user.email,
      existingCredentialIds
    );

    // Store challenge temporarily (in production, use Redis)
    // For now, we'll include it in the response and expect it back
    // In a real app, store this server-side with an expiry

    return NextResponse.json(options);
  } catch (error) {
    console.error('Passkey registration options error:', error);
    return NextResponse.json(
      { error: 'Failed to generate registration options' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { verifyRegistration, base64URLDecode } from '@/lib/passkeys';
import type { RegistrationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/register/verify
// Verify and store a new passkey
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response, expectedChallenge, deviceName } = body;

    if (!email || !response || !expectedChallenge) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Verify the registration response
    const verification = await verifyRegistration(
      response as RegistrationResponseJSON,
      expectedChallenge
    );

    if (!verification.verified || !verification.registrationInfo) {
      return NextResponse.json(
        { error: verification.error || 'Registration verification failed' },
        { status: 400 }
      );
    }

    // Find user
    const user = await db.adminUser.findUnique({
      where: { email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'User not found' },
        { status: 404 }
      );
    }

    // Store the credential
    const { credentialID, credentialPublicKey, counter } = verification.registrationInfo;

    await db.passkeyCredential.create({
      data: {
        credentialId: credentialID,
        userId: user.id,
        publicKey: Buffer.from(credentialPublicKey),
        counter,
        deviceType: response.authenticatorAttachment || 'cross-platform',
        deviceName: deviceName || 'Unknown Device',
      },
    });

    return NextResponse.json({
      success: true,
      message: 'Passkey registered successfully',
    });
  } catch (error) {
    console.error('Passkey registration verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey registration' },
      { status: 500 }
    );
  }
}

