import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { verifyAuthentication } from '@/lib/passkeys';
import { createSession, setSessionCookie } from '@/lib/auth';
import type { AuthenticationResponseJSON } from '@simplewebauthn/types';

// POST /api/admin/passkey/auth/verify
// Verify passkey authentication and create session
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, response, expectedChallenge } = body;

    if (!email || !response || !expectedChallenge) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Find the credential
    const credentialId = response.id;
    const passkey = await db.passkeyCredential.findUnique({
      where: { credentialId },
      include: { user: true },
    });

    if (!passkey || passkey.user.email !== email) {
      return NextResponse.json(
        { error: 'Invalid credential' },
        { status: 401 }
      );
    }

    // Verify the authentication response
    const verification = await verifyAuthentication(
      response as AuthenticationResponseJSON,
      expectedChallenge,
      {
        id: passkey.credentialId,
        publicKey: new Uint8Array(passkey.publicKey),
        counter: passkey.counter,
      }
    );

    if (!verification.verified) {
      return NextResponse.json(
        { error: verification.error || 'Authentication failed' },
        { status: 401 }
      );
    }

    // Update counter to prevent replay attacks
    if (verification.newCounter !== undefined) {
      await db.passkeyCredential.update({
        where: { id: passkey.id },
        data: {
          counter: verification.newCounter,
          lastUsedAt: new Date(),
        },
      });
    }

    // Update user's last login
    await db.adminUser.update({
      where: { id: passkey.userId },
      data: { lastLoginAt: new Date() },
    });

    // Create session
    const token = await createSession(
      passkey.userId,
      passkey.user.email,
      passkey.user.name || 'Admin'
    );
    await setSessionCookie(token);

    return NextResponse.json({
      success: true,
      user: {
        id: passkey.userId,
        email: passkey.user.email,
        name: passkey.user.name,
      },
    });
  } catch (error) {
    console.error('Passkey authentication verification error:', error);
    return NextResponse.json(
      { error: 'Failed to verify passkey authentication' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { getSession } from '@/lib/auth';
import { processFileUpload, formatFileSize, getFileCategory } from '@/lib/upload';

// POST /api/upload - Upload files
export async function POST(request: NextRequest) {
  try {
    // Check authentication
    const session = await getSession();
    if (!session) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Parse form data
    const formData = await request.formData();
    const files = formData.getAll('files') as File[];

    if (!files || files.length === 0) {
      return NextResponse.json(
        { error: 'No files provided' },
        { status: 400 }
      );
    }

    // Process each file
    const results = await Promise.all(
      files.map(async (file) => {
        const uploadResult = await processFileUpload(file);

        if (!uploadResult.success) {
          return {
            success: false,
            originalName: file.name,
            error: uploadResult.error,
          };
        }

        // Save to database
        const media = await db.media.create({
          data: {
            id: uploadResult.id,
            filename: uploadResult.filename!,
            originalName: uploadResult.originalName,
            mimeType: uploadResult.mimeType,
            category: getFileCategory(uploadResult.mimeType),
            size: uploadResult.size,
            width: uploadResult.width,
            height: uploadResult.height,
            duration: uploadResult.duration,
            url: uploadResult.url!,
            thumbnailUrl: uploadResult.thumbnailUrl,
            uploadedById: session.userId,
          },
        });

        return {
          success: true,
          media: {
            id: media.id,
            filename: media.filename,
            originalName: media.originalName,
            url: media.url,
            thumbnailUrl: media.thumbnailUrl,
            category: media.category,
            size: formatFileSize(media.size),
            width: media.width,
            height: media.height,
          },
        };
      })
    );

    const successful = results.filter(r => r.success);
    const failed = results.filter(r => !r.success);

    return NextResponse.json({
      success: true,
      uploaded: successful.length,
      failed: failed.length,
      results,
    });
  } catch (error) {
    console.error('Upload error:', error);
    return NextResponse.json(
      { error: 'Failed to process upload' },
      { status: 500 }
    );
  }
}

// GET /api/upload - List media files
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const category = searchParams.get('category');
    const folder = searchParams.get('folder');
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '20');
    const search = searchParams.get('search');

    // Build where clause
    const where: any = {};
    if (category) where.category = category;
    if (folder) where.folder = folder;
    if (search) {
      where.OR = [
        { originalName: { contains: search, mode: 'insensitive' } },
        { tags: { contains: search, mode: 'insensitive' } },
      ];
    }

    // Get total count
    const total = await db.media.count({ where });

    // Get media files
    const media = await db.media.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      skip: (page - 1) * limit,
      take: limit,
      include: {
        _count: {
          select: {
            articleUsages: true,
            projectUsages: true,
          },
        },
      },
    });

    return NextResponse.json({
      success: true,
      media,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error('Media list error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch media' },
      { status: 500 }
    );
  }
}

// DELETE /api/upload - Delete media files
export async function DELETE(request: NextRequest) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { ids } = body;

    if (!ids || !Array.isArray(ids) || ids.length === 0) {
      return NextResponse.json(
        { error: 'No media IDs provided' },
        { status: 400 }
      );
    }

    // Delete from database (cascade will clean up relations)
    const result = await db.media.deleteMany({
      where: { id: { in: ids } },
    });

    // TODO: Also delete files from storage

    return NextResponse.json({
      success: true,
      deleted: result.count,
    });
  } catch (error) {
    console.error('Media delete error:', error);
    return NextResponse.json(
      { error: 'Failed to delete media' },
      { status: 500 }
    );
  }
}

'use client';

import { useCallback, useState, useMemo } from 'react';
import { useDropzone } from 'react-dropzone';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Upload,
  X,
  FileImage,
  FileVideo,
  FileAudio,
  FileText,
  CheckCircle,
  AlertCircle,
  Loader2,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { cn } from '@/lib/utils';
import { formatFileSize, getFileCategory, isPreviewable } from '@/lib/upload';

interface UploadFile {
  id: string;
  file: File;
  preview?: string;
  progress: number;
  status: 'pending' | 'uploading' | 'success' | 'error';
  error?: string;
  result?: {
    id: string;
    url: string;
    thumbnailUrl?: string;
  };
}

interface MediaUploaderProps {
  onUploadComplete?: (files: UploadFile[]) => void;
  maxFiles?: number;
  className?: string;
}

export function MediaUploader({
  onUploadComplete,
  maxFiles = 10,
  className,
}: MediaUploaderProps) {
  const [files, setFiles] = useState<UploadFile[]>([]);
  const [isUploading, setIsUploading] = useState(false);

  const onDrop = useCallback((acceptedFiles: File[]) => {
    const newFiles: UploadFile[] = acceptedFiles.map((file) => ({
      id: Math.random().toString(36).substring(7),
      file,
      preview: isPreviewable(file.type) && file.type.startsWith('image/')
        ? URL.createObjectURL(file)
        : undefined,
      progress: 0,
      status: 'pending',
    }));

    setFiles((prev) => [...prev, ...newFiles].slice(0, maxFiles));
  }, [maxFiles]);

  const { getRootProps, getInputProps, isDragActive, isDragReject } = useDropzone({
    onDrop,
    maxFiles: maxFiles - files.length,
    accept: {
      'image/*': ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.avif', '.svg'],
      'video/*': ['.mp4', '.webm', '.ogg'],
      'audio/*': ['.mp3', '.wav', '.ogg', '.webm'],
      'application/pdf': ['.pdf'],
      'application/msword': ['.doc'],
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx'],
    },
  });

  const removeFile = (id: string) => {
    setFiles((prev) => {
      const file = prev.find((f) => f.id === id);
      if (file?.preview) {
        URL.revokeObjectURL(file.preview);
      }
      return prev.filter((f) => f.id !== id);
    });
  };

  const uploadFiles = async () => {
    if (files.length === 0) return;

    setIsUploading(true);

    const formData = new FormData();
    const pendingFiles = files.filter((f) => f.status === 'pending');

    pendingFiles.forEach((file) => {
      formData.append('files', file.file);
    });

    try {
      const response = await fetch('/api/upload', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      if (data.success) {
        // Update file statuses
        setFiles((prev) =>
          prev.map((file) => {
            const result = data.results.find(
              (r: any) => r.success && r.media.originalName === file.file.name
            );
            if (result) {
              return {
                ...file,
                status: 'success',
                progress: 100,
                result: result.media,
              };
            }
            const failed = data.results.find(
              (r: any) => !r.success && r.originalName === file.file.name
            );
            if (failed) {
              return {
                ...file,
                status: 'error',
                error: failed.error,
              };
            }
            return file;
          })
        );

        onUploadComplete?.(files);
      }
    } catch (error) {
      console.error('Upload error:', error);
      setFiles((prev) =>
        prev.map((file) =>
          file.status === 'pending'
            ? { ...file, status: 'error', error: 'Upload failed' }
            : file
        )
      );
    } finally {
      setIsUploading(false);
    }
  };

  const clearAll = () => {
    files.forEach((file) => {
      if (file.preview) {
        URL.revokeObjectURL(file.preview);
      }
    });
    setFiles([]);
  };

  const getFileIcon = (type: string) => {
    const category = getFileCategory(type);
    switch (category) {
      case 'image':
        return <FileImage className="h-8 w-8 text-blue-500" />;
      case 'video':
        return <FileVideo className="h-8 w-8 text-purple-500" />;
      case 'audio':
        return <FileAudio className="h-8 w-8 text-orange-500" />;
      default:
        return <FileText className="h-8 w-8 text-gray-500" />;
    }
  };

  return (
    <div className={cn('space-y-4', className)}>
      {/* Dropzone */}
      <div
        {...getRootProps()}
        className={cn(
          'border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors',
          isDragActive && !isDragReject && 'border-primary bg-primary/5',
          isDragReject && 'border-destructive bg-destructive/5',
          !isDragActive && 'border-muted-foreground/25 hover:border-muted-foreground/50'
        )}
      >
        <input {...getInputProps()} />
        <Upload className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
        <p className="text-lg font-medium mb-2">
          {isDragActive ? 'Drop files here' : 'Drag & drop files here'}
        </p>
        <p className="text-sm text-muted-foreground">
          or click to select files
        </p>
        <p className="text-xs text-muted-foreground mt-2">
          Images, videos, audio, and documents up to 50MB
        </p>
      </div>

      {/* File List */}
      <AnimatePresence>
        {files.length > 0 && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="space-y-2"
          >
            {files.map((file) => (
              <motion.div
                key={file.id}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
                className={cn(
                  'flex items-center gap-3 p-3 rounded-lg border',
                  file.status === 'success' && 'border-green-500/30 bg-green-500/5',
                  file.status === 'error' && 'border-red-500/30 bg-red-500/5',
                  file.status === 'pending' && 'border-border bg-muted/50'
                )}
              >
                {/* Preview / Icon */}
                <div className="relative w-16 h-16 rounded-lg overflow-hidden bg-muted flex-shrink-0">
                  {file.preview ? (
                    <img
                      src={file.preview}
                      alt={file.file.name}
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center">
                      {getFileIcon(file.file.type)}
                    </div>
                  )}
                  {file.status === 'success' && (
                    <div className="absolute inset-0 bg-green-500/20 flex items-center justify-center">
                      <CheckCircle className="h-6 w-6 text-green-500" />
                    </div>
                  )}
                </div>

                {/* File Info */}
                <div className="flex-1 min-w-0">
                  <p className="font-medium truncate">{file.file.name}</p>
                  <p className="text-sm text-muted-foreground">
                    {formatFileSize(file.file.size)}
                  </p>
                  {file.status === 'uploading' && (
                    <Progress value={file.progress} className="h-1 mt-2" />
                  )}
                  {file.error && (
                    <p className="text-xs text-red-500 mt-1">{file.error}</p>
                  )}
                </div>

                {/* Actions */}
                <Button
                  variant="ghost"
                  size="icon"
                  className="flex-shrink-0"
                  onClick={() => removeFile(file.id)}
                  disabled={isUploading}
                >
                  <X className="h-4 w-4" />
                </Button>
              </motion.div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Actions */}
      {files.length > 0 && (
        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={clearAll}
            disabled={isUploading}
          >
            Clear All
          </Button>
          <Button
            onClick={uploadFiles}
            disabled={
              isUploading ||
              files.every((f) => f.status !== 'pending')
            }
          >
            {isUploading ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Uploading...
              </>
            ) : (
              <>
                <Upload className="h-4 w-4 mr-2" />
                Upload {files.filter((f) => f.status === 'pending').length} files
              </>
            )}
          </Button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import {
  Search,
  Filter,
  Grid3X3,
  List,
  Trash2,
  Copy,
  Check,
  Image,
  Video,
  FileAudio,
  FileText,
  Upload,
  X,
  MoreHorizontal,
  FolderOpen,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent } from '@/components/ui/card';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { MediaUploader } from '@/components/admin/media-uploader';
import { cn } from '@/lib/utils';
import { formatFileSize } from '@/lib/upload';

interface Media {
  id: string;
  filename: string;
  originalName: string;
  mimeType: string;
  category: string;
  size: number;
  width?: number;
  height?: number;
  url: string;
  thumbnailUrl?: string;
  createdAt: string;
  _count: {
    articleUsages: number;
    projectUsages: number;
  };
}

const container = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.05 },
  },
};

const item = {
  hidden: { opacity: 0, y: 20 },
  show: { opacity: 1, y: 0 },
};

export default function MediaLibraryPage() {
  const [media, setMedia] = useState<Media[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedItems, setSelectedItems] = useState<Set<string>>(new Set());
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [uploaderOpen, setUploaderOpen] = useState(false);

  const fetchMedia = useCallback(async () => {
    try {
      const params = new URLSearchParams();
      if (selectedCategory !== 'all') {
        params.append('category', selectedCategory);
      }
      if (searchQuery) {
        params.append('search', searchQuery);
      }

      const response = await fetch(`/api/upload?${params.toString()}`);
      const data = await response.json();

      if (data.success) {
        setMedia(data.media);
      }
    } catch (error) {
      console.error('Failed to fetch media:', error);
    } finally {
      setLoading(false);
    }
  }, [selectedCategory, searchQuery]);

  useEffect(() => {
    fetchMedia();
  }, [fetchMedia]);

  const toggleSelection = (id: string) => {
    setSelectedItems((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const selectAll = () => {
    setSelectedItems(new Set(media.map((m) => m.id)));
  };

  const clearSelection = () => {
    setSelectedItems(new Set());
  };

  const deleteSelected = async () => {
    if (selectedItems.size === 0) return;

    if (!confirm(`Delete ${selectedItems.size} items?`)) return;

    try {
      const response = await fetch('/api/upload', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ids: Array.from(selectedItems) }),
      });

      const data = await response.json();

      if (data.success) {
        setMedia((prev) => prev.filter((m) => !selectedItems.has(m.id)));
        setSelectedItems(new Set());
      }
    } catch (error) {
      console.error('Delete failed:', error);
    }
  };

  const copyUrl = (url: string, id: string) => {
    navigator.clipboard.writeText(url);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const getFileIcon = (category: string) => {
    switch (category) {
      case 'image':
        return <Image className="h-8 w-8" />;
      case 'video':
        return <Video className="h-8 w-8" />;
      case 'audio':
        return <FileAudio className="h-8 w-8" />;
      default:
        return <FileText className="h-8 w-8" />;
    }
  };

  const categories = [
    { value: 'all', label: 'All Files', icon: FolderOpen },
    { value: 'image', label: 'Images', icon: Image },
    { value: 'video', label: 'Videos', icon: Video },
    { value: 'audio', label: 'Audio', icon: FileAudio },
    { value: 'document', label: 'Documents', icon: FileText },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Media Library</h1>
          <p className="text-muted-foreground">
            Manage your images, videos, and documents
          </p>
        </div>
        <Dialog open={uploaderOpen} onOpenChange={setUploaderOpen}>
          <DialogTrigger asChild>
            <Button>
              <Upload className="h-4 w-4 mr-2" />
              Upload Files
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Upload Media</DialogTitle>
            </DialogHeader>
            <MediaUploader
              onUploadComplete={() => {
                fetchMedia();
                setUploaderOpen(false);
              }}
            />
          </DialogContent>
        </Dialog>
      </div>

      {/* Filters & Search */}
      <div className="flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search files..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Tabs value={selectedCategory} onValueChange={setSelectedCategory}>
            <TabsList>
              {categories.map((cat) => (
                <TabsTrigger key={cat.value} value={cat.value}>
                  <cat.icon className="h-4 w-4 mr-2" />
                  {cat.label}
                </TabsTrigger>
              ))}
            </TabsList>
          </Tabs>
        </div>
      </div>

      {/* Bulk Actions */}
      {selectedItems.size > 0 && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="flex items-center gap-4 p-4 bg-primary/5 rounded-lg"
        >
          <span className="text-sm font-medium">
            {selectedItems.size} selected
          </span>
          <Button variant="ghost" size="sm" onClick={clearSelection}>
            <X className="h-4 w-4 mr-2" />
            Clear
          </Button>
          <Button
            variant="destructive"
            size="sm"
            onClick={deleteSelected}
          >
            <Trash2 className="h-4 w-4 mr-2" />
            Delete
          </Button>
        </motion.div>
      )}

      {/* View Toggle */}
      <div className="flex justify-end gap-2">
        <Button
          variant={viewMode === 'grid' ? 'default' : 'outline'}
          size="icon"
          onClick={() => setViewMode('grid')}
        >
          <Grid3X3 className="h-4 w-4" />
        </Button>
        <Button
          variant={viewMode === 'list' ? 'default' : 'outline'}
          size="icon"
          onClick={() => setViewMode('list')}
        >
          <List className="h-4 w-4" />
        </Button>
      </div>

      {/* Media Grid/List */}
      {loading ? (
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {Array.from({ length: 12 }).map((_, i) => (
            <div
              key={i}
              className="aspect-square rounded-lg bg-muted animate-pulse"
            />
          ))}
        </div>
      ) : media.length === 0 ? (
        <div className="text-center py-12">
          <FolderOpen className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
          <p className="text-muted-foreground">No media files found</p>
          <Button
            variant="outline"
            className="mt-4"
            onClick={() => setUploaderOpen(true)}
          >
            <Upload className="h-4 w-4 mr-2" />
            Upload your first file
          </Button>
        </div>
      ) : (
        <motion.div
          variants={container}
          initial="hidden"
          animate="show"
          className={cn(
            viewMode === 'grid'
              ? 'grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4'
              : 'space-y-2'
          )}
        >
          {media.map((item) => (
            <motion.div key={item.id} variants={item}>
              {viewMode === 'grid' ? (
                <Card
                  className={cn(
                    'group cursor-pointer transition-all',
                    selectedItems.has(item.id) && 'ring-2 ring-primary'
                  )}
                  onClick={() => toggleSelection(item.id)}
                >
                  <CardContent className="p-0">
                    <div className="aspect-square relative overflow-hidden rounded-t-lg bg-muted">
                      {item.category === 'image' ? (
                        <img
                          src={item.thumbnailUrl || item.url}
                          alt={item.originalName}
                          className="w-full h-full object-cover"
                          loading="lazy"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          {getFileIcon(item.category)}
                        </div>
                      )}
                      {/* Overlay */}
                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/40 transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100">
                        <div className="flex gap-2">
                          <Button
                            size="icon"
                            variant="secondary"
                            onClick={(e) => {
                              e.stopPropagation();
                              copyUrl(item.url, item.id);
                            }}
                          >
                            {copiedId === item.id ? (
                              <Check className="h-4 w-4" />
                            ) : (
                              <Copy className="h-4 w-4" />
                            )}
                          </Button>
                          <Button
                            size="icon"
                            variant="destructive"
                            onClick={(e) => {
                              e.stopPropagation();
                              setSelectedItems(new Set([item.id]));
                              deleteSelected();
                            }}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                    </div>
                    <div className="p-3">
                      <p className="font-medium truncate text-sm">
                        {item.originalName}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {formatFileSize(item.size)}
                        {item.width && item.height && (
                          <span className="ml-2">
                            • {item.width}×{item.height}
                          </span>
                        )}
                      </p>
                    </div>
                  </CardContent>
                </Card>
              ) : (
                <div
                  className={cn(
                    'flex items-center gap-4 p-3 rounded-lg border transition-all',
                    selectedItems.has(item.id)
                      ? 'border-primary bg-primary/5'
                      : 'border-border hover:bg-muted/50'
                  )}
                  onClick={() => toggleSelection(item.id)}
                >
                  <div className="w-12 h-12 rounded bg-muted flex items-center justify-center flex-shrink-0">
                    {item.category === 'image' ? (
                      <img
                        src={item.thumbnailUrl || item.url}
                        alt={item.originalName}
                        className="w-full h-full object-cover rounded"
                      />
                    ) : (
                      getFileIcon(item.category)
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">{item.originalName}</p>
                    <p className="text-sm text-muted-foreground">
                      {formatFileSize(item.size)}
                      {' • '}
                      {new Date(item.createdAt).toLocaleDateString()}
                      {item._count.articleUsages > 0 && (
                        <span className="ml-2 text-blue-500">
                          Used in {item._count.articleUsages} article
                          {item._count.articleUsages > 1 ? 's' : ''}
                        </span>
                      )}
                    </p>
                  </div>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem
                        onClick={() => copyUrl(item.url, item.id)}
                      >
                        <Copy className="h-4 w-4 mr-2" />
                        Copy URL
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        className="text-destructive"
                        onClick={() => {
                          setSelectedItems(new Set([item.id]));
                          deleteSelected();
                        }}
                      >
                        <Trash2 className="h-4 w-4 mr-2" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              )}
            </motion.div>
          ))}
        </motion.div>
      )}
    </div>
  );
}

